    <div style="font-size:12px;color:var(--gray-l);margin-bottom:10px">\uC2A4\uD2B8\uB9AC\uBA38\uD0ED\uC758 \uCE74\uB4DC/\uD5E4\uB354/\uD234\uBC14 \uBD84\uC704\uAE30\uC640 \uC804\uCCB4 \uBC30\uCE58 \uBC00\uB3C4\uB97C \uCE74\uD14C\uACE0\uB9AC\uC5D0 \uB9DE\uAC8C \uC870\uC808\uD569\uB2C8\uB2E4. \uAE30\uBCF8 \uBDF0 \uC124\uC815\uACFC \uBCC4\uB3C4\uB85C \uB514\uC790\uC778/\uB808\uC774\uC544\uC6C3\uC744 \uB530\uB85C \uBC14\uAFC9\uB2C8\uB2E4.</div>
